import React, { useEffect, useState } from 'react';
import axios from 'axios';


/**
 * Formulário de Agendamento de Paciente
 * - Fluxo adaptado para: Novo, Retorno e Solicitar para Recepção
 * - Paciente SEMPRE precisa ser selecionado, mas pode ser cadastrado direto sem duplicidade
 * - Operador é obrigatório, auxiliares são opcionais
 * - Botão muda texto conforme fluxo
 */

function FormAgendamento({ onNovoAgendamento, agendamentoEditando, onFimEdicao }) {
  // Tipo de atendimento: 'Novo', 'Retorno', 'Solicitar'
  const [tipoAtendimento, setTipoAtendimento] = useState('Novo');

  // Pacientes (seleção e cadastro rápido)
  const [pacientes, setPacientes] = useState([]);
  const [pacienteId, setPacienteId] = useState('');
  const [nomePaciente, setNomePaciente] = useState('');
  const [telefone, setTelefone] = useState('');

  // Listas para selects
  const [disciplinas, setDisciplinas] = useState([]);
  const [alunos, setAlunos] = useState([]);
  // Campos do formulário
  const [disciplinaId, setDisciplinaId] = useState('');
  const [data, setData] = useState('');
  const [hora, setHora] = useState('');
  const [observacoes, setObservacoes] = useState('');
  // Operador (obrigatório) e auxiliares (opcionais)
  const [operadorId, setOperadorId] = useState('');
  const [auxiliar1Id, setAuxiliar1Id] = useState('');
  const [auxiliar2Id, setAuxiliar2Id] = useState('');
  // Mensagem de sucesso/erro
  const [mensagem, setMensagem] = useState('');

  // Carrega pacientes ao abrir o form
  useEffect(() => {
    axios.get('/api/pacientes').then(res => setPacientes(res.data));
  }, []);

  // Carregar listas (disciplinas e alunos) ao iniciar o componente
  useEffect(() => {
    axios.get('/api/disciplinas').then(res => setDisciplinas(res.data));
    axios.get('/api/alunos').then(res => setAlunos(res.data));
  }, []);

  // Preencher dados se estiver editando um agendamento
  useEffect(() => {
    if (agendamentoEditando) {
      setTipoAtendimento(
        agendamentoEditando.status === 'Solicitado'
          ? 'Solicitar'
          : agendamentoEditando.status
      );
      setDisciplinaId(agendamentoEditando.disciplina_id || '');
      setPacienteId(agendamentoEditando.paciente_id || '');
      setNomePaciente(agendamentoEditando.nome_paciente || '');
      setTelefone(agendamentoEditando.telefone || '');
      setData(agendamentoEditando.data ? agendamentoEditando.data.slice(0, 10) : '');
      setHora(agendamentoEditando.hora || '19:00');
      setObservacoes(agendamentoEditando.observacoes || '');

      // Aqui está o segredo: use exatamente os nomes usados no backend/model/banco!
      setOperadorId(
        agendamentoEditando.aluno_id
          ? String(agendamentoEditando.aluno_id)
          : agendamentoEditando.operador_id || ''
      );
      setAuxiliar1Id(
        agendamentoEditando.auxiliar1_id
          ? String(agendamentoEditando.auxiliar1_id)
          : ''
      );
      setAuxiliar2Id(
        agendamentoEditando.auxiliar2_id
          ? String(agendamentoEditando.auxiliar2_id)
          : ''
      );
    } else {
      setTipoAtendimento('Novo');
      setDisciplinaId('');
      setPacienteId('');
      setNomePaciente('');
      setTelefone('');
      setData('');
      setHora('19:00');
      setObservacoes('');
      setOperadorId('');
      setAuxiliar1Id('');
      setAuxiliar2Id('');
    }
  }, [agendamentoEditando]);


  // Seleciona paciente no select
  const handleSelecionarPaciente = (e) => {
    setPacienteId(e.target.value);
    const selecionado = pacientes.find(p => String(p.id) === e.target.value);
    if (selecionado) {
      setNomePaciente(selecionado.nome);
      setTelefone(selecionado.telefone);
    } else {
      setNomePaciente('');
      setTelefone('');
    }
  };

  // Cadastro rápido de paciente sem duplicidade
  const handleCadastrarPaciente = () => {
    if (!nomePaciente || !telefone) {
      setMensagem('Informe nome e telefone do paciente!');
      return;
    }
    axios.post('/api/pacientes', { nome: nomePaciente, telefone })
      .then(res => {
        axios.get('/api/pacientes').then(resList => {
          setPacientes(resList.data);
          setPacienteId(String(res.data.id));
          setMensagem('Paciente cadastrado com sucesso!');
        });
      })
      .catch(() => {
        setMensagem('Erro ao cadastrar paciente. Confira se o telefone já não existe.');
      });
  };

  // Envio do agendamento para backend
  const handleSubmit = (e) => {
    e.preventDefault();
    // Validação básica
    if (!disciplinaId) { setMensagem("Disciplina obrigatória"); return; }
    if (!pacienteId && tipoAtendimento !== 'Solicitar') { setMensagem("Paciente obrigatório"); return; }
    if (!operadorId) { setMensagem("Selecione um operador"); return; }

    // Dados para backend
   const dados = {
  disciplina_id: disciplinaId,
  paciente_id: tipoAtendimento === 'Solicitar' ? null : pacienteId,
  nome_paciente: tipoAtendimento === 'Solicitar' ? null : nomePaciente,
  telefone: tipoAtendimento === 'Solicitar' ? null : telefone,
  data: tipoAtendimento === 'Solicitar' ? null : data,
  hora: "19:00",
  observacoes: tipoAtendimento === 'Solicitar' ? null : observacoes,
  aluno_id: operadorId,
  auxiliar1_id: auxiliar1Id,
  auxiliar2_id: auxiliar2Id,
  status: tipoAtendimento === 'Solicitar' ? 'Solicitado' : tipoAtendimento,
  solicitado_por_recepcao: tipoAtendimento === 'Solicitar',
};



    // POST se novo, PUT se edição
    if (agendamentoEditando) {
      axios.put(`/api/agendamentos/${agendamentoEditando.id}`, dados)
        .then(() => {
          setMensagem('Agendamento atualizado!');
          onNovoAgendamento && onNovoAgendamento();
          onFimEdicao && onFimEdicao();
        })
        .catch(() => setMensagem('Erro ao atualizar agendamento.'));
    } else {
      axios.post('/api/agendamentos', dados)
        .then(() => {
          setMensagem('Agendamento cadastrado!');
          onNovoAgendamento && onNovoAgendamento();
          // Limpa o formulário
          setDisciplinaId('');
          setPacienteId('');
          setNomePaciente('');
          setTelefone('');
          setData('');
          setHora('');
          setObservacoes('');
          setOperadorId('');
          setAuxiliar1Id('');
          setAuxiliar2Id('');
        })
        .catch(() => setMensagem('Erro ao cadastrar agendamento.'));
    }
  };

  // Renderização
  return (
  <div className="bg-white rounded-xl shadow-lg p-8 max-w-3xl mx-auto">
    <form onSubmit={handleSubmit}>
      <h2 className="text-2xl font-bold mb-6 text-gray-700">Agendar Paciente</h2>

      {/* Tipo de atendimento */}
      <div className="flex gap-2 mb-4">
        <button
          type="button"
          onClick={() => setTipoAtendimento('Novo')}
          className={`px-4 py-2 rounded ${tipoAtendimento === 'Novo' ? 'bg-blue-600 text-white' : 'bg-gray-200'}`}
        >
          Novo
        </button>
        <button
          type="button"
          onClick={() => setTipoAtendimento('Retorno')}
          className={`px-4 py-2 rounded ${tipoAtendimento === 'Retorno' ? 'bg-blue-600 text-white' : 'bg-gray-200'}`}
        >
          Retorno
        </button>
        <button
          type="button"
          onClick={() => setTipoAtendimento('Solicitar')}
          className={`px-4 py-2 rounded ${tipoAtendimento === 'Solicitar' ? 'bg-blue-600 text-white' : 'bg-gray-200'}`}
        >
          Solicitar para Recepção
        </button>
      </div>

      {/* Grid do formulário */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {/* Disciplina */}
        <div>
          <label className="block mb-1 font-medium">Disciplina</label>
          <select
            required
            className="w-full border rounded px-3 py-2"
            value={disciplinaId}
            onChange={e => setDisciplinaId(e.target.value)}
          >
            <option value="">Selecione</option>
            {disciplinas.map(d => (
              <option key={d.id} value={d.id}>{d.nome}</option>
            ))}
          </select>
        </div>

        {/* Paciente */}
        {tipoAtendimento !== 'Solicitar' && (
          <div>
            <label className="block mb-1 font-medium">Paciente</label>
            <select className="w-full border rounded px-3 py-2"
              value={pacienteId}
              onChange={handleSelecionarPaciente}
              required
            >
              <option value="">Selecione</option>
              {pacientes.map(p => (
                <option key={p.id} value={p.id}>{p.nome} - {p.telefone}</option>
              ))}
            </select>
            {!pacienteId && (
              <div className="mt-2 flex flex-col gap-2">
                <input
                  className="border rounded px-3 py-2"
                  placeholder="Nome do Paciente"
                  value={nomePaciente}
                  onChange={e => setNomePaciente(e.target.value)}
                  required
                />
                <input
                  className="border rounded px-3 py-2"
                  placeholder="Telefone"
                  value={telefone}
                  onChange={e => setTelefone(e.target.value)}
                  required
                />
                <button
                  type="button"
                  className="bg-blue-500 text-white px-3 py-2 rounded"
                  onClick={handleCadastrarPaciente}
                >
                  Cadastrar Paciente
                </button>
              </div>
            )}
            {pacienteId && (
              <div className="mt-2 flex flex-col gap-2">
                <input
                  className="border rounded px-3 py-2 bg-gray-100"
                  value={nomePaciente}
                  readOnly
                />
                <input
                  className="border rounded px-3 py-2 bg-gray-100"
                  value={telefone}
                  readOnly
                />
              </div>
            )}
          </div>
        )}

        {/* Data e Hora */}
        {tipoAtendimento !== 'Solicitar' && (
          <>
            <div>
              <label className="block mb-1 font-medium">Data do Atendimento</label>
              <input
                type="date"
                className="w-full border rounded px-3 py-2"
                value={data}
                onChange={e => setData(e.target.value)}
                required
              />
            </div>
            <div>
              <label className="block mb-1 font-medium">Hora do Atendimento</label>
              <input
                type="time"
                className="w-full border rounded px-3 py-2"
                value={hora}
                onChange={e => setHora(e.target.value)}
                required
              />
            </div>
          </>
        )}

        {/* Observações */}
        <div className="md:col-span-2">
          <label className="block mb-1 font-medium">Outras Informações</label>
          <textarea
            className="w-full border rounded px-3 py-2"
            value={observacoes}
            onChange={e => setObservacoes(e.target.value)}
            placeholder="Observações relevantes"
          />
        </div>
      </div>

      {/* Alunos */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mt-6">
        <div>
          <label className="block mb-1 font-medium">Operador *</label>
          <select
            required
            className="w-full border rounded px-3 py-2"
            value={operadorId}
            onChange={e => setOperadorId(e.target.value)}
          >
            <option value="">Selecione o operador</option>
            {alunos.map(a => (
              <option key={a.id} value={a.id}>{a.nome}</option>
            ))}
          </select>
        </div>
        <div>
          <label className="block mb-1 font-medium">Auxiliar 1</label>
          <select
            className="w-full border rounded px-3 py-2"
            value={auxiliar1Id}
            onChange={e => setAuxiliar1Id(e.target.value)}
          >
            <option value="">Selecione o auxiliar</option>
            {alunos.map(a => (
              <option key={a.id} value={a.id}>{a.nome}</option>
            ))}
          </select>
        </div>
        <div>
          <label className="block mb-1 font-medium">Auxiliar 2</label>
          <select
            className="w-full border rounded px-3 py-2"
            value={auxiliar2Id}
            onChange={e => setAuxiliar2Id(e.target.value)}
          >
            <option value="">Selecione o auxiliar</option>
            {alunos.map(a => (
              <option key={a.id} value={a.id}>{a.nome}</option>
            ))}
          </select>
        </div>
      </div>

      {/* Botões */}
      <div className="flex gap-4 mt-8">
        <button
          type="submit"
          className="bg-blue-600 hover:bg-blue-700 text-white font-bold py-2 px-6 rounded"
        >
          {tipoAtendimento === 'Solicitar' ? 'Solicitar para Recepção' : 'Agendar Paciente'}
        </button>
        {agendamentoEditando && (
          <button
            type="button"
            className="bg-gray-400 text-white px-4 py-2 rounded"
            onClick={onFimEdicao}
          >
            Cancelar
          </button>
        )}
      </div>

      {/* Mensagem */}
      {mensagem && <p className="mt-4 text-red-600">{mensagem}</p>}
    </form>
  </div>
);

}

export default FormAgendamento;
